class Solution {
public:
    int maximumLength(string s) {
        unordered_map<char, int> count;
        int maxLen = 0;
        for (char c : s) {
            count[c]++;
        }
        for (auto it : count) {
            if (it.second >= 3) {
                maxLen = max(maxLen, it.first - 'a' + 1);
            }
        }
        return maxLen;
    }
};
